// Anti-manipulation: per-user, per-ticker, per-day limits
const MAX_DAILY_IMPACT = 0.10;          // 10% max cumulative price move
const MAX_TRADES_PER_TICKER_24H = 10;   // Max buys or sells per ticker per rolling 24h

// Admin price protection: after an admin manually sets a price, automated
// price movers (bot trader, market maker) leave that ticker alone for this
// long so they can't claw the adjustment back. Resets each time admin re-sets.
const ADMIN_PRICE_PROTECTION_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

// Anti-manipulation: reduced price impact for brand-new accounts.
// Mirrors src/constants/economy.js — keep both in sync.
const NEW_ACCOUNT_IMPACT_PERIOD_DAYS = 3;  // ramps over the first 3 days
const NEW_ACCOUNT_MIN_IMPACT_FACTOR = 0.1; // 10% impact at day 0 → 100% at day 3

// Anti-alt: hard cap on accounts per IP, enforced at signup AND trade.
// ADMIN_UID is always exempt. Flip IP_ACCOUNT_CAP_ENABLED to false to disable the
// hard block instantly (e.g. if client IPs turn out unreliable) without a code change.
const MAX_ACCOUNTS_PER_IP = 2;
const IP_ACCOUNT_CAP_ENABLED = true;
// A deleted account keeps holding its per-IP slot for this long, then the slot
// frees up. Stops the pump → delete → remake loop (a month's wait per cycle makes
// it worthless) while still letting genuine deleters rejoin later.
const IP_SLOT_RELEASE_MS = 30 * 24 * 60 * 60 * 1000; // 30 days
// A Discord account linked to a now-deleted Stockism account is blocked from
// linking or creating a new one for this long. Mirrors IP_SLOT_RELEASE_MS: it
// kills the create → grab the verified $3k starting cash → gamble → delete →
// remake loop (and one aged Discord spawning troll accounts) by making each cycle
// cost a month's wait. The $3k bonus is one-time per live account, so within this
// window it can never be re-granted either.
const DISCORD_RELINK_COOLDOWN_MS = 30 * 24 * 60 * 60 * 1000; // 30 days

const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000;
const ONE_WEEK_MS           = 7 * 24 * 60 * 60 * 1000;
const THIRTY_DAYS_MS        = 30 * 24 * 60 * 60 * 1000;
const NINETY_DAYS_MS        = 90 * 24 * 60 * 60 * 1000;

// Read cap for the public-profile sparkline query (keeps per-view Firestore
// reads bounded no matter how many history points an account has).
const PUBLIC_PROFILE_SPARKLINE_MAX_POINTS = 150;

// ============================================
// WEEKLY TRADING HALT (Thursday 13:00–21:00 UTC)
// ============================================
const WEEKLY_HALT_START_MINUTE = 780;  // 13 * 60
const WEEKLY_HALT_END_MINUTE   = 1260; // 21 * 60
const PRE_MARKET_START_MINUTE  = 1230; // 20:30 UTC
const PRE_MARKET_LOCK_MINUTE   = 1255; // 20:55 UTC — no placements or cancellations after this; auction settles 20:56
// Max-buy headroom for pre-market orders: opening ask can sit up to ~5%
// (auction impact cap) + spread above the queue-time price, so placement
// validates against price * this buffer. Keep in sync with src/constants/economy.js.
const PRE_MARKET_MAX_BUY_BUFFER = 1.06;
// A single ticker's total short value (existing + new) can't exceed this
// fraction of portfolio equity.
const SHORT_CONCENTRATION_CAP = 0.5;

const isWeeklyTradingHalt = () => {
  const now = new Date();
  if (now.getUTCDay() !== 4) return false;
  const utcMins = now.getUTCHours() * 60 + now.getUTCMinutes();
  return utcMins >= WEEKLY_HALT_START_MINUTE && utcMins < WEEKLY_HALT_END_MINUTE;
};

