// ============================================
// IPO
// ============================================
const IPO_PRICE_JUMP = 0.15; // 15% price bump when IPO fully subscribed
// IPO-bought shares are locked from selling until ipoEndsAt + this buffer, so the
// guaranteed +15% launch pop can't be flipped for a risk-free profit. Measured
// from ipoEndsAt because shares already can't trade before launch: a last-second
// buyer (who triggers an early sellout) still has to hold through the float window,
// and an early buyer holds through the IPO they opted into.
const IPO_SELL_LOCKUP_MS = 24 * 60 * 60 * 1000; // 24 hours
// Shares bought with margin are locked from re-selling this long, so borrowed
// money can't be used to spike a stock and bail before the price reverts.
const MARGIN_SELL_LOCKUP_MS = 36 * 60 * 60 * 1000; // 36 hours

// ============================================
// EVENT PREDICTION MARKETS (long-term, AMM-priced)
// ============================================
// LMSR liquidity parameter (b). Bigger = steadier prices and a larger bounded
// house subsidy. Max the house can ever lose on a market is b * ln(numOutcomes)
// (~$3,466 for a yes/no market at b=5000). Seeded generously on purpose: stable
// prices and generous payouts build trust, and a deep book stops one big early
// bet from yanking the line.
const EVENT_AMM_LIQUIDITY = 5000;
const EVENT_MIN_BUYIN = 1; // minimum dollar cost of a single buy (avoids dust)

